// // This mux selects the second input when sel is 0 and the first input when sel is 1
module Mux2to1 (
    input sel,
    input [7:0] a,
    input [7:0] b,
    output reg [7:0] y
);

    always @(*) begin
        if (sel)
            y <= b;
        else
            y <= a;
    end
endmodule
